  1→import { Injectable, Logger } from '@nestjs/common';
  2→
  3→import { AlgoliaService } from '@modules/algolia/algolia.service';
  4→import { CondensedFeaturesService } from '@modules/db/condensed-features/condensed-features.service';
  5→import { ICondensedFeaturesBase } from '@modules/db/condensed-features/types/condensed-features.base.interface';
  6→import { ProductAnnualSalesService } from '@modules/db/product-annual-sales/product-annual-sales.service';
  7→import { StylesService } from '@modules/db/styles/styles.service';
  8→import { StylesHashService } from '@modules/db/styles-hash/styles-hash.service';
  9→import { IStylesHashBase } from '@modules/db/styles-hash/types/styles-hash.base.interface';
 10→import { StylesMvService } from '@modules/db/styles-mv/styles-mv.service';
 11→import { MmsService } from '@modules/mms/mms.service';
 12→import { OpenAIService } from '@modules/rest/open-ai/open-ai.service';
 13→
 14→import { convertRGBToString } from '@utils/color-match.util';
 15→import { compareHashes } from '@utils/compare-hashes.util';
 16→import { getEnv } from '@utils/get-env-variable.util';
 17→import { hashFromObject } from '@utils/hash-from-object.unit';
 18→import { withRetry } from '@utils/retry.util';
 19→
 20→import {
 21→	ALGOLIA_OBJECT_ID_SUFFIXES,
 22→	DEFAULT_PRICING_ALGORITHM,
 23→	EXCLUDED_CAT_NAMES,
 24→	STYLES_HASHING_ALGORITHM,
 25→	styleStatus,
 26→	TAXONOMY_CAT_IDS,
 27→} from '@constants/common.constant';
 28→import { MMS_IMAGES_LAMBDA_HOST } from '@constants/env-variables.constant';
 29→
 30→import {
 31→	Breadcrumb,
 32→	FeaturesRelatedFields,
 33→	MMSAllStyleCategory,
 34→	MMSResponse,
 35→	MMSStyleToProcess,
 36→} from '@interfaces/mms-style-to-process.interface';
 37→
 38→import { LogExecution } from '@decorators/log-execution.decorator';
 39→
 40→@Injectable()
 41→export class ProcessStyleService {
 42→	private readonly logger = new Logger(ProcessStyleService.name);
 43→	private readonly mmsImagesLambdaHost = getEnv({ key: MMS_IMAGES_LAMBDA_HOST });
 44→
 45→	constructor(
 46→		private readonly stylesHashService: StylesHashService,
 47→		private readonly condensedFeaturesService: CondensedFeaturesService,
 48→		private readonly OpenAIService: OpenAIService,
 49→		private readonly algoliaService: AlgoliaService,
 50→		private readonly mmsService: MmsService,
 51→		private readonly productAnnualSalesService: ProductAnnualSalesService,
 52→		private readonly stylesService: StylesService,
 53→		private readonly stylesMvService: StylesMvService,
 54→	) {}
 55→
 56→	@LogExecution({
 57→		paramFormatter: (params) => params,
 58→		responseFormatter: (response) => response,
 59→		logErrToRollbar: false,
 60→		logParams: false,
 61→		logResponse: false,
 62→		logLongExecution: false,
 63→	})
 64→	public async process({
 65→		style,
 66→		allCategories,
 67→	}: {
 68→		style: MMSStyleToProcess;
 69→		allCategories: MMSAllStyleCategory[];
 70→	}): Promise<boolean> {
 71→		try {
 72→			if (!this.isProductAllowedToProcess(style)) {
 73→				this.logger.debug(`Style ${style.id} is not allowed to process.`);
 74→				await Promise.all([
 75→					this.deleteFromAlgoliaIndex({ styleId: style.id }),
 76→					this.deleteCondensedFeatures({ styleId: style.id }),
 77→				]);
 78→				return false;
 79→			}
 80→
 81→			const featuresRelatedFields = this.extractFeaturesRelatedFields({
 82→				style,
 83→				allCategories,
 84→			});
 85→
 86→			const isProductActive = this.checkIsProductActive({
 87→				status: style.status,
 88→				colors: style.colors,
 89→			});
 90→
 91→			await this.saveStyleToDatabase({ style, allCategories, isProductActive });
 92→
 93→			const newHash = hashFromObject({
 94→				obj: featuresRelatedFields as unknown as Record<string, unknown>,
 95→			});
 96→			const storedHash = await this.getStoredHash({ styleId: style.id });
 97→
 98→			const isCondensedFeaturesExists =
 99→				await this.condensedFeaturesService.getCondensedFeature({
100→					styleId: style.id,
101→				});
102→
103→			if (!storedHash) {
104→				if (!isCondensedFeaturesExists) {
105→					this.logger.debug(
106→						`Style ${style.id}: no hash, no features. Creating new features`,
107→					);
108→
109→					const condensedFeatures = isProductActive
110→						? await this.generateLLMFeatures({ style, featuresRelatedFields })
111→						: [];
112→					await this.saveCondensedFeatures({ styleId: style.id, condensedFeatures });
113→					await this.createHash({ styleId: style.id, hash: newHash });
114→					if (isProductActive) {
115→						await this.generateAndSaveEmbeddingText({
116→							style,
117→							allCategories,
118→							condensedFeatures,
119→						});
120→					}
121→					await this.updateAlgoliaIndex({
122→						style,
123→						allCategories,
124→						condensedFeatures,
125→					});
126→				} else {
127→					this.logger.debug(
128→						`Style ${style.id}: no hash, but features exist. Generating hash`,
129→					);
130→					await this.createHash({ styleId: style.id, hash: newHash });
131→					await this.updateAlgoliaIndex({
132→						style,
133→						allCategories,
134→						condensedFeatures: isCondensedFeaturesExists.condensed_features,
135→					});
136→				}
137→
138→				return true;
139→			} else if (storedHash && !compareHashes({ hash1: newHash, hash2: storedHash })) {
140→				this.logger.debug(`Style ${style.id}: hash changed, updating features and index`);
141→
142→				const condensedFeatures = isProductActive
143→					? await this.generateLLMFeatures({ style, featuresRelatedFields })
144→					: (isCondensedFeaturesExists?.condensed_features ?? []);
145→				await this.updateStoredHash({ styleId: style.id, hash: newHash });
146→				await this.updateCondensedFeatures({ styleId: style.id, condensedFeatures });
147→				if (isProductActive) {
148→					await this.generateAndSaveEmbeddingText({
149→						style,
150→						allCategories,
151→						condensedFeatures,
152→					});
153→				}
154→				await this.updateAlgoliaIndex({
155→					style,
156→					allCategories,
157→					condensedFeatures,
158→				});
159→				return true;
160→			} else if (storedHash && !isCondensedFeaturesExists) {
161→				this.logger.debug(
162→					`Style ${style.id}: hash exists, but no features exist. Creating new features`,
163→				);
164→				const condensedFeatures = isProductActive
165→					? await this.generateLLMFeatures({ style, featuresRelatedFields })
166→					: [];
167→				await this.saveCondensedFeatures({ styleId: style.id, condensedFeatures });
168→				if (isProductActive) {
169→					await this.generateAndSaveEmbeddingText({
170→						style,
171→						allCategories,
172→						condensedFeatures,
173→					});
174→				}
175→				await this.updateAlgoliaIndex({
176→					style,
177→					allCategories,
178→					condensedFeatures,
179→				});
180→				return true;
181→			}
182→
183→			await this.updateAlgoliaIndex({
184→				style,
185→				allCategories,
186→				condensedFeatures: isCondensedFeaturesExists?.condensed_features ?? [],
187→			});
188→			this.logger.debug(`Style ${style.id}: hash is the same, no changes needed`);
189→			return false;
190→		} catch (error) {
191→			this.logger.error(`Error processing style ${style.id}:`, error);
192→			throw error;
193→		}
194→	}
