196→	public async fetchStylesFromMMS({
197→		page,
198→		perPage,
199→		timeoutMs,
200→	}: {
201→		page: number;
202→		perPage?: number;
203→		timeoutMs?: number;
204→	}): Promise<MMSResponse> {
205→		return this.mmsService.fetchStyles({
206→			page,
207→			...(perPage !== undefined && { perPage }),
208→			...(timeoutMs !== undefined && { timeoutMs }),
209→		});
210→	}
