212→	private checkIsProductActive({
213→		status,
214→		colors,
215→	}: {
216→		status: string;
217→		colors: MMSStyleToProcess['colors'];
218→	}): boolean {
219→		if (status === styleStatus.ACTIVE) {
220→			if (colors?.length) {
221→				return colors.some((color) => color.status === styleStatus.ACTIVE);
222→			}
223→
224→			return true;
225→		}
226→
227→		return false;
228→	}
