230→	private isProductAllowedToProcess(style: MMSStyleToProcess): boolean {
231→		const name = String(style.name);
232→		const formattedName = name.toLowerCase();
233→		const isCanadian =
234→			formattedName.includes('canada') || formattedName.includes('canadian');
235→
236→		return !isCanadian;
237→	}
