239→	private async getStoredHash({
240→		styleId,
241→	}: {
242→		styleId: number;
243→	}): Promise<IStylesHashBase['hash'] | null> {
244→		const hashRecord = await this.stylesHashService.getStyleHash({ styleId });
245→
246→		if (!hashRecord) {
247→			this.logger.debug(`No stored hash found for style ${styleId}`);
248→			return null;
249→		}
250→
251→		return hashRecord.hash;
252→	}
253→
254→	private async createHash({
255→		styleId,
256→		hash,
257→	}: {
258→		styleId: number;
259→		hash: string;
260→	}): Promise<void> {
261→		await this.stylesHashService.createStyleHash({
262→			data: {
263→				style_id: styleId,
264→				hash,
265→				hashing_algorithm: STYLES_HASHING_ALGORITHM,
266→			},
267→		});
268→		this.logger.debug(`Created new hash for style ${styleId}: ${hash}`);
269→	}
270→
271→	private async updateStoredHash({
272→		styleId,
273→		hash,
274→	}: {
275→		styleId: number;
276→		hash: string;
277→	}): Promise<void> {
278→		await this.stylesHashService.updateHashValue({
279→			styleId,
280→			hash,
281→			algorithm: STYLES_HASHING_ALGORITHM,
282→		});
283→		this.logger.debug(`Updated hash for style ${styleId} to ${hash}`);
284→	}
