286→	private async saveStyleToDatabase({
287→		style,
288→		allCategories,
289→		isProductActive,
290→	}: {
291→		style: MMSStyleToProcess;
292→		allCategories: MMSAllStyleCategory[];
293→		isProductActive: boolean;
294→	}): Promise<void> {
295→		try {
296→			const categoryIds = this.extractCategoryIds({ style });
297→			const categoriesWithParentsIds = this.extractCategoriesWithParents({
298→				categoryIds,
299→				allCategories,
300→			});
301→
302→			const purchasesCount =
303→				await this.productAnnualSalesService.getPurchasesCountForLatestYear({
304→					styleId: Number(style.id),
305→				});
306→
307→			const styleData = {
308→				style_id: style.id,
309→				primary_category_id: style.primary_category_id ?? 0,
310→				root_category_id: this.getRootCategoryId({ style, allCategories }),
311→				purchases_count: purchasesCount,
312→				categories_ids: categoryIds,
313→				categories_with_parents_ids: categoriesWithParentsIds,
314→				is_active: isProductActive,
315→				name: style.name,
316→				decoration_method: style.decoration_method,
317→				features: style.features,
318→				general_comments: style.general_comments,
319→				manufacturer: style.manufacturer,
320→				minimum_quantity: style.min_qty,
321→				rating_count: style.rating_count,
322→				rating_score: Number(style.rating_score),
323→				sizes: (style.style_sizes ?? []).map((size) => size.name),
324→				style_type: style.style_type,
325→				price_level: style.price_level,
326→				primary_category_name: style.primary_category?.name ?? '',
327→				default_quote_qty: style.primary_category?.default_quote_qty ?? 1,
328→				product_type: style.product_type,
329→				style_card_image_url: this.generateStyleCardImageUrl({
330→					styleId: style.id,
331→					catalogDetailImageMd5: style.catalog_detail_image_md5,
332→				}),
333→				broad_category_names: this.getBroadCategoryNames({
334→					categories: style.categories,
335→					allCategories,
336→				}),
337→				sub_category_names: this.getStylesSubcategories({
338→					categories: style.categories,
339→					allCategories,
340→				}),
341→				turn_time: style.turntime ? Number(style.turntime.standard) : 0,
342→				rush_turn_time: style.turntime ? Number(style.turntime.rush) : 0,
343→				no_minimum: style.has_singles_enabled_colors,
344→				link_path: this.calculateLink({ style, allCategories })?.path ?? '',
345→				brand: this.getBrand([style.brand]),
346→				min_qty: style.min_qty,
347→			};
348→
349→			if (!style.colors?.length) {
350→				this.logger.debug(`Style ${style.id} has no colors to save`);
351→				return;
352→			}
353→
354→			const colors = style.colors.map((color) => {
355→				const isActive = color.status === styleStatus.ACTIVE;
356→				const hasRgb = Array.isArray(color.rbgs) && color.rbgs[0];
357→				const colorRgb =
358→					hasRgb && color.rbgs[0] ? convertRGBToString(color.rbgs[0]) : null;
359→
360→				return {
361→					color_id: color.id,
362→					color_rgb: colorRgb,
363→					color_name: color.name,
364→					is_active: Boolean(isActive && hasRgb),
365→					image_url: color.image_url,
366→				};
367→			});
368→
369→			const defaultUnitPrices = this.getDefaultUnitPrices({ style }).map((priceData) => ({
370→				quantity: priceData.quantity,
371→				price: Number(priceData.price),
372→				regular_unit_price: priceData.regular_unit_price
373→					? Number(priceData.regular_unit_price)
374→					: null,
375→				algorithm: priceData.algorithm,
376→			}));
377→
378→			await this.stylesService.saveCompleteStyle({
379→				styleData,
380→				colors,
381→				defaultUnitPrices,
382→			});
383→
384→			this.logger.debug(`Successfully saved style ${style.id} to database`);
385→		} catch (error: unknown) {
386→			const err = error instanceof Error ? error : new Error(String(error));
387→			this.logger.error(`Failed to save style ${style.id} to database: ${err.message}`);
388→			throw err;
389→		}
390→	}
