392→	private async generateLLMFeatures({
393→		style,
394→		featuresRelatedFields,
395→	}: {
396→		style: MMSStyleToProcess;
397→		featuresRelatedFields: FeaturesRelatedFields;
398→	}): Promise<string[]> {
399→		try {
400→			const result = await withRetry({
401→				fn: () => this.OpenAIService.generateProductFeatures({ productInfo: style }),
402→				options: { retryCount: 2 },
403→			});
404→
405→			if (result.error) {
406→				this.logger.error(
407→					`Failed to generate features for style ${style.id}: ${result.error}`,
408→				);
409→				throw new Error(`Failed to generate features: ${result.error}`);
410→			}
411→
412→			return result.description ?? [];
413→		} catch (error) {
414→			const errorMessage = error instanceof Error ? error.message : String(error);
415→			const isTokenLimitError = errorMessage.includes('maximum context length');
416→
417→			if (isTokenLimitError) {
418→				this.logger.warn(
419→					`Token limit exceeded for style ${style.id}, retrying with reduced fields`,
420→				);
421→
422→				const reducedResult = await withRetry({
423→					fn: () =>
424→						this.OpenAIService.generateProductFeatures({
425→							productInfo: featuresRelatedFields as unknown as MMSStyleToProcess,
426→						}),
427→					options: { retryCount: 2 },
428→				});
429→
430→				if (reducedResult.error) {
431→					throw new Error(`Failed to generate features: ${reducedResult.error}`);
432→				}
433→
434→				this.logger.log(
435→					`Successfully generated features for style ${style.id} using reduced fields`,
436→				);
437→				return reducedResult.description ?? [];
438→			}
439→
440→			this.logger.error(`Failed to generate features for style ${style.id}:`, error);
441→			throw error;
442→		}
443→	}
