478→	private async deleteCondensedFeatures({
479→		styleId,
480→	}: {
481→		styleId: ICondensedFeaturesBase['style_id'];
482→	}): Promise<void> {
483→		await this.condensedFeaturesService.deleteCondensedFeature({ styleId });
484→		this.logger.debug(`Deleted condensed features for style ${styleId}`);
