487→	private async generateAndSaveEmbeddingText({
488→		style,
489→		allCategories,
490→		condensedFeatures,
491→	}: {
492→		style: MMSStyleToProcess;
493→		allCategories: MMSAllStyleCategory[];
494→		condensedFeatures: string[];
495→	}): Promise<void> {
496→		try {
497→			const product = {
498→				name: style.name,
499→				product_type: style.product_type,
500→				style_type: style.style_type,
501→				primary_category_name: style.primary_category?.name ?? null,
502→				sub_category_names: this.getStylesSubcategories({
503→					categories: style.categories,
504→					allCategories,
505→				}),
506→				broad_category_names: this.getBroadCategoryNames({
507→					categories: style.categories,
508→					allCategories,
509→				}),
510→				features: style.features,
511→				general_comments: style.general_comments,
512→				decoration_method: style.decoration_method,
513→				manufacturer: style.manufacturer,
514→				brand: this.getBrand([style.brand]),
515→				condensed_features: condensedFeatures,
516→				sizes: (style.style_sizes ?? []).map((size) => size.name),
517→			};
518→
519→			const result = await withRetry({
520→				fn: () => this.OpenAIService.generateEmbeddingText({ product }),
521→				options: { retryCount: 2 },
522→			});
523→
524→			await this.stylesMvService.updateEmbeddingText({
525→				styleId: style.id,
526→				embeddingText: result.text,
527→			});
528→
529→			this.logger.debug(`Embedding text saved for style ${style.id}`);
530→		} catch (error) {
531→			this.logger.error(
532→				`Failed to generate embedding text for style ${style.id}: ${error instanceof Error ? error.message : String(error)}`,
533→			);
534→		}
535→	}
