537→	private async updateAlgoliaIndex({
538→		style,
539→		allCategories,
540→		condensedFeatures,
541→	}: {
542→		style: MMSStyleToProcess;
543→		allCategories: MMSAllStyleCategory[];
544→		condensedFeatures?: string[];
545→	}): Promise<void> {
546→		const algoliaStyle = {
547→			objectID: String(style.id),
548→			name: style.name,
549→			primary_category_id: style.primary_category_id,
550→			brand: this.getBrand([style.brand]),
551→			condensed_features: condensedFeatures ?? [],
552→			sub_category_names: this.getStylesSubcategories({
553→				categories: style.categories,
554→				allCategories,
555→			}),
556→			no_minimum: style.has_singles_enabled_colors ? 1 : 0,
557→			price_level: style.price_level,
558→			product_id: style.id,
559→			product_type: style.product_type,
560→			style_card_image_url: this.generateStyleCardImageUrl({
561→				styleId: style.id,
562→				catalogDetailImageMd5: style.catalog_detail_image_md5,
563→			}),
564→		};
565→
566→		const objects = ALGOLIA_OBJECT_ID_SUFFIXES.map((suffix) => ({
567→			...algoliaStyle,
568→			objectID: `${style['objectID']}-${suffix}`,
569→			index_suffix: suffix,
570→		}));
571→
572→		await this.algoliaService.saveObjects({ objects });
573→	}
