575→	private async deleteFromAlgoliaIndex({ styleId }: { styleId: number }): Promise<void> {
576→		const objectIds = ALGOLIA_OBJECT_ID_SUFFIXES.map((suffix) => `${styleId}-${suffix}`);
577→		await this.algoliaService.deleteObjects({ objectIds });
578→		this.logger.debug(`Deleted style ${styleId} from Algolia index (all suffixes)`);
579→	}
