581→	private extractFeaturesRelatedFields({
582→		style,
583→		allCategories,
584→	}: {
585→		style: MMSStyleToProcess;
586→		allCategories: MMSAllStyleCategory[];
587→	}): FeaturesRelatedFields {
588→		return {
589→			name: style.name,
590→			decoration_method: style.decoration_method,
591→			features: style.features,
592→			general_comments: style.general_comments,
593→			manufacturer: style.manufacturer,
594→			sizes: (style.style_sizes ?? []).map((size) => size.name),
595→			style_type: style.style_type,
596→			price_level: style.price_level,
597→			primary_category_name: style.primary_category?.name ?? '',
598→			product_type: style.product_type,
599→			broad_category_names: this.getBroadCategoryNames({
600→				categories: style.categories,
601→				allCategories,
602→			}),
603→			sub_category_names: this.getStylesSubcategories({
604→				categories: style.categories,
605→				allCategories,
606→			}),
607→			turn_time: style.turntime ? Number(style.turntime.standard) : 0,
608→			rush_turn_time: style.turntime ? Number(style.turntime.rush) : 0,
609→			no_minimum: style.has_singles_enabled_colors ? 1 : 0,
610→		};
611→	}
