613→	private getDefaultUnitPrices({
614→		style,
615→	}: {
616→		style: MMSStyleToProcess;
617→	}): MMSStyleToProcess['default_unit_prices'] {
618→		return style.default_unit_prices.reduce<MMSStyleToProcess['default_unit_prices']>(
619→			(acc, pricesObj) => {
620→				if (pricesObj.algorithm !== DEFAULT_PRICING_ALGORITHM) {
621→					return acc;
622→				}
623→
624→				acc.push({
625→					quantity: pricesObj.quantity,
626→					price: pricesObj.price,
