651→	private getBroadCategoryNames({
652→		categories,
653→		allCategories,
654→	}: {
655→		styleId?: number;
656→		categories: MMSStyleToProcess['categories'];
657→		allCategories: MMSAllStyleCategory[];
658→	}): string[] {
659→		const activeCategories = categories
660→			.map((cat) => {
661→				const fullCategory = allCategories.find((c) => c._id === cat.parent_id);
662→				if (fullCategory) {
663→					cat['parent'] = fullCategory;
664→				}
665→				return cat;
666→			})
667→			.filter((cat) => cat.active);
668→
669→		const allParents = activeCategories
670→			.map((category) => category['parent'] ?? { ...category, _id: category.id })
671→			.filter(Boolean) as MMSAllStyleCategory[];
672→
673→		const uniqueParents = allParents.reduce<MMSAllStyleCategory[]>((acc, parent) => {
674→			if (TAXONOMY_CAT_IDS.includes(parent._id)) {
675→				return acc;
676→			}
677→
678→			if (!acc.some((p) => p._id === parent._id)) {
679→				acc.push(parent);
680→			}
681→
682→			return acc;
683→		}, []);
684→
685→		const names = uniqueParents
686→			.map((parent) => parent['name'])
687→			.filter((name) => name && !EXCLUDED_CAT_NAMES.includes(name as string)) as string[];
688→
689→		return [...new Set(names)];
690→	}
