692→	private getStylesSubcategories({
693→		categories,
694→		allCategories,
695→	}: {
696→		categories: MMSStyleToProcess['categories'];
697→		allCategories: MMSAllStyleCategory[];
698→	}): string[] {
699→		const activeCategories = categories.filter((cat) => cat.active && cat.parent_id);
700→
701→		const childCategories: string[] = [];
702→
703→		for (const category of activeCategories) {
704→			const hasChildren = allCategories.some((cat) => cat['parent_id'] === category.id);
705→
706→			if (!hasChildren && category.name) {
707→				childCategories.push(category.name);
708→			}
709→		}
710→
711→		return [...new Set(childCategories)];
712→	}
