718→	private calculateLink({
719→		style,
720→		allCategories,
721→	}: {
722→		style: MMSStyleToProcess;
723→		allCategories: MMSAllStyleCategory[];
724→	}): Breadcrumb | null {
725→		function urlFriendly(str: string): string {
726→			return str
727→				.toLowerCase()
728→				.replace(/&reg;/g, '®')
729→				.replace(/\//g, '-')
730→				.replace(/\s+/g, '-')
731→				.replace(/[^\+\-0-9_a-z]/g, '')
732→				.replace(/^-+|-+$/g, '')
733→				.replace(/-+/g, '-');
734→		}
735→
736→		const primaryCategory = style.primary_category;
737→
738→		if (!primaryCategory) {
739→			return null;
740→		}
741→
742→		const primaryCatParent = allCategories.find(
743→			(cat) => cat._id === primaryCategory.parent_id,
744→		);
745→
746→		const primaryCatParentName = primaryCatParent?.['name'] as string;
747→		const categoryName = primaryCategory.name;
748→
749→		const firstPartLink = !primaryCatParent
750→			? '/products'
751→			: `/products/${urlFriendly(primaryCatParentName)}`;
752→
753→		const path = `${firstPartLink}/${urlFriendly(categoryName)}/${urlFriendly(style.name)}/${style.id}`;
754→
755→		return {
756→			name: style.name,
757→			path: path,
758→		};
759→	}
760→
761→	private extractCategoryIds({ style }: { style: MMSStyleToProcess }): number[] {
762→		const activeCategories = style.categories.filter((cat) => cat.active);
763→		return activeCategories.map((cat) => cat.id);
764→	}
765→
766→	private extractCategoriesWithParents({
767→		categoryIds,
768→		allCategories,
769→	}: {
770→		categoryIds: number[];
771→		allCategories: MMSAllStyleCategory[];
772→	}): number[] {
773→		const allCategoryIds = new Set<number>();
774→
775→		for (const categoryId of categoryIds) {
776→			allCategoryIds.add(categoryId);
777→
778→			const parentIds = this.getAllParentCategoryIds({ categoryId, allCategories });
779→			for (const parentId of parentIds) {
780→				allCategoryIds.add(parentId);
781→			}
782→		}
783→
784→		return Array.from(allCategoryIds).sort((a, b) => a - b);
785→	}
786→
787→	private getAllParentCategoryIds({
788→		categoryId,
789→		allCategories,
790→	}: {
791→		categoryId: number;
792→		allCategories: MMSAllStyleCategory[];
793→	}): number[] {
794→		const parents: number[] = [];
795→		const category = allCategories.find((cat) => cat._id === categoryId);
796→
797→		if (!category?.['parent_id']) {
798→			return parents;
799→		}
800→
801→		let currentParentId = category['parent_id'] as number;
802→
803→		while (currentParentId) {
804→			parents.push(currentParentId);
805→
806→			const parentCategory = allCategories.find((cat) => cat._id === currentParentId);
807→			if (!parentCategory?.['parent_id']) {
808→				break;
809→			}
810→
811→			currentParentId = parentCategory['parent_id'] as number;
812→		}
813→
814→		return parents;
815→	}
816→
817→	private getRootCategoryId({
818→		style,
819→		allCategories,
820→	}: {
821→		style: MMSStyleToProcess;
822→		allCategories: MMSAllStyleCategory[];
823→	}): number | null {
824→		if (!style.primary_category) {
825→			return null;
826→		}
827→
828→		const primaryCategory = allCategories.find(
829→			(cat) => cat._id === style.primary_category_id,
830→		);
831→		if (!primaryCategory) {
832→			return null;
833→		}
834→
835→		let currentCategory = primaryCategory;
836→		while (currentCategory['parent_id']) {
837→			const parentCategory = allCategories.find(
838→				(cat) => cat._id === currentCategory['parent_id'],
839→			);
840→			if (!parentCategory) break;
841→			currentCategory = parentCategory;
842→		}
843→
844→		return !currentCategory['parent_id'] ? currentCategory._id : null;
845→	}
846→}
