213→		size = 20,
214→	}: {
215→		queryText: string;
216→		size?: number;
217→	}): Promise<IOpensearchProduct[]> {
218→		const normalizedQuery = this.normalizeQuery({ text: queryText });
219→		const hits = await this.opensearchService.search({
220→			indexName: this.indexName,
221→			searchPipeline: 'hybrid-search-pipeline',
222→			body: {
223→				size,
224→				query: {
225→					hybrid: {
226→						queries: [
227→							{
228→								bool: {
229→									should: [
230→										{ match_phrase: { name: { query: normalizedQuery, boost: 5 } } },
231→										{ match: { name: { query: normalizedQuery, boost: 3 } } },
232→										{ match: { features: { query: normalizedQuery, boost: 1 } } },
233→									],
234→									filter: [{ term: { status: 'active' } }],
235→								},
236→							},
237→							{
238→								neural: {
239→									product_embedding: {
240→										query_text: normalizedQuery,
241→										model_id: this.getModelId(),
242→										k: size,
243→										filter: { term: { status: 'active' } },
244→									},
245→								},
246→							},
247→						],
248→					},
249→				},
250→				_source: { excludes: ['product_embedding', 'combined_text_for_embedding'] },
251→			},
252→		});
253→
254→		return hits.slice(0, size).map((hit) => ({
255→			...(hit._source as IOpensearchProduct),
256→			_id: hit._id,
257→		}));
258→	}
