260→	private normalizeCondensedFeatures({
261→		condensedFeatures,
262→	}: {
263→		condensedFeatures: unknown;
264→	}): string[] | null {
265→		if (condensedFeatures === null || condensedFeatures === undefined) {
266→			return null;
267→		}
268→
269→		if (typeof condensedFeatures === 'string') {
270→			return [condensedFeatures];
271→		}
272→
273→		if (Array.isArray(condensedFeatures)) {
274→			return condensedFeatures.map(String);
275→		}
276→
277→		if (typeof condensedFeatures === 'object') {
278→			return Object.values(condensedFeatures).flatMap((value: unknown) =>
279→				Array.isArray(value) ? value.map(String) : [String(value)],
280→			);
281→		}
282→
283→		return [JSON.stringify(condensedFeatures)];
284→	}
