286→	private buildCombinedTextForEmbedding({ style }: { style: IStylesMvBase }): string {
287→		const normalizedCondensedFeatures = this.normalizeCondensedFeatures({
288→			condensedFeatures: style.condensed_features,
289→		});
290→
291→		const cleanText = ({ text }: { text: string | null | undefined }): string => {
292→			if (!text) return '';
293→			return text
294→				.replace(/\r\n|\r|\n/g, ' ')
295→				.replace(/[*#]+\s?/g, '')
296→				.replace(/<[^>]*>/g, '')
297→				.replace(/\s{2,}/g, ' ')
298→				.trim();
299→		};
300→
301→		const parts: string[] = [];
302→
303→		if (style.name) parts.push(style.name + '.');
304→
305→		const cats = [
306→			style.product_type,
307→			style.style_type,
308→			style.primary_category_name,
309→		].filter(Boolean);
310→		if (cats.length) parts.push(cats.join(', ') + '.');
311→
312→		const features = cleanText({ text: style.features });
313→		if (features) parts.push(features + '.');
314→
315→		const description = normalizedCondensedFeatures
316→			? cleanText({ text: normalizedCondensedFeatures.join(', ') })
317→			: '';
318→		if (description) parts.push(description);
319→
320→		if (style.decoration_method) parts.push(`Decoration: ${style.decoration_method}.`);
321→		if (style.manufacturer) parts.push(`Made by ${style.manufacturer}.`);
322→		if (style.brand?.length) parts.push(`Brand: ${style.brand.join(', ')}.`);
323→
324→		return parts.join(' ');
325→	}
